  export async function seedEntitlements(): Promise<void> {
    const dbUrl = process.env.DATABASE_URL
    if (!dbUrl) {
      console.error('[seed-entitlements] DATABASE_URL not set, skipping')
      return
    }

    const client = new pg.Client({ connectionString: dbUrl })
    await client.connect()

    try {
      const countResult = await client.query('SELECT count(*) FROM leave_balances WHERE year = 2026')
      const existingCount = parseInt(countResult.rows[0].count, 10)
      if (existingCount >= balanceData.length) {
        console.log(`[seed-entitlements] ${existingCount} balance records already exist, skipping seed`)
        return
      }

      console.log(`[seed-entitlements] Found ${existingCount} balances, seeding ${balanceData.length}...`)

      await client.query(NEW_LEAVE_TYPES_SQL)

      const ltResult = await client.query('SELECT id, code FROM leave_types')
      const codeToId = new Map<string, number>(ltResult.rows.map((r: { id: number; code: string }) => [r.code, r.id]))

      const userResult = await client.query('SELECT id, email FROM users WHERE is_active = true')
      const emailToId = new Map<string, number>(userResult.rows.map((r: { id: number; email: string }) => [r.email, r.id]))

      const batchSize = 50
      for (let i = 0; i < balanceData.length; i += batchSize) {
        const batch = balanceData.slice(i, i + batchSize)
        const values = batch
          .map(b => {
            const userId = emailToId.get(b.email)
            const leaveTypeId = codeToId.get(b.leaveTypeCode)
            if (!userId || !leaveTypeId) return null
            return `(${userId}, ${leaveTypeId}, 2026, ${b.entitled}, ${b.used}, 0, ${b.carried}, ${b.adjustments})`
          })
          .filter(Boolean)
          .join(',\n')

        if (!values) continue

        await client.query(`
          INSERT INTO leave_balances (user_id, leave_type_id, year, entitled, used, pending, carried, adjustments)
          VALUES ${values}
          ON CONFLICT (user_id, leave_type_id, year) DO UPDATE SET
            entitled = EXCLUDED.entitled,
            used = EXCLUDED.used,
            carried = EXCLUDED.carried,
            adjustments = EXCLUDED.adjustments
        `)
      }

      console.log(`[seed-entitlements] Successfully seeded ${balanceData.length} balance records`)
    } catch (err) {
      console.error('[seed-entitlements] Error seeding entitlements:', err)
    } finally {
      await client.end()
    }
  }
  